.darma-loader-darma-custom-514 {color: var(--loader-color, #16a34a);
   width: 32px;
   height: 16px;
   display: flex;
}
.darma-loader-darma-custom-514:before, .darma-loader-darma-custom-514:after  {
  content: "";
   flex: 1;
   background: var(--loader-color, #16a34a);
   transform-origin: top right;
   animation: darma-loader-darma-custom-514-l10-1 2s infinite;
}
.darma-loader-darma-custom-514:after  {
  background: var(--loader-secondary-color, #86efac);
   transform-origin: top left;
   animation-delay: .25s;
}
@keyframes darma-loader-darma-custom-514-l10-1  {
  0%,5% {transform: rotate(0)}
20%,30% {transform: rotate(90deg)}
45%,55% {transform: rotate(180deg)}
70%,80% {transform: rotate(270deg)}
95%,100% {transform: rotate(360deg)}
}

